class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

def sameTree(data):
    def build_tree(level_order):
        if not level_order:
            return None
        nodes = [TreeNode(int(x)) if x != 'null' else None for x in level_order]
        for i in range(len(nodes)):
            if nodes[i] is not None:
                if 2 * i + 1 < len(nodes):
                    nodes[i].left = nodes[2 * i + 1]
                if 2 * i + 2 < len(nodes):
                    nodes[i].right = nodes[2 * i + 2]
        return nodes[0]

    trees = data.split('\n')
    tree1 = build_tree(trees[0].split())
    tree2 = build_tree(trees[1].split())

    def is_same_tree(node1, node2):
        if not node1 and not node2:
            return True
        if not node1 or not node2:
            return False
        if node1.val != node2.val:
            return False
        return is_same_tree(node1.left, node2.left) and is_same_tree(node1.right, node2.right)

    return is_same_tree(tree1, tree2)

